mapper.select:
SELECT t.*, f.begin_balance AS beginBalance, f.end_balance AS endBalance, p.third_party_sn AS thirdPartySn FROM purchase_order t LEFT JOIN energy_account_order_flow f ON f.consume_id = t.order_sn LEFT JOIN order_third_party_prepay p ON p.order_sn = t.order_sn AND p.is_deleted = 0
t.is_deleted = 0
AND t.order_type = #{qo.orderType}
AND t.order_status = #{qo.orderStatus}
AND t.order_sn LIKE CONCAT('%', #{qo.orderSnLike}, '%')
AND p.third_party_sn LIKE CONCAT('%', #{qo.thirdPartySnLike}, '%')
AND t.owner_name LIKE CONCAT('%', #{qo.enterpriseNameLike}, '%')
AND t.owner_type = #{qo.ownerType}
AND t.order_create_time >= #{qo.createStartTime}
AND t.order_create_time < #{qo.createEndTime}
AND t.payment_channel = #{qo.paymentChannel}
ORDER BY t.order_create_time DESC
